CREATE TYPE "Role" AS ENUM ('ADMIN','SUPERVISOR','OPERADOR');
CREATE TYPE "CampaignStatus" AS ENUM ('RASCUNHO','ATIVA','PAUSADA','ENCERRADA');
CREATE TYPE "LeadStatus" AS ENUM ('NOVO','EM_FILA','LIGANDO','ATENDIDO','NAO_ATENDEU','OCUPADO','NUMERO_INVALIDO','CAIXA_POSTAL','RETORNO','INTERESSADO','SEM_INTERESSE','MATRICULADO','NAO_LIGAR_NOVAMENTE','ERRO_CHAMADA');
CREATE TYPE "CallStatus" AS ENUM ('CREATED','STARTED','RINGING','ANSWERED','COMPLETED','FAILED','CANCELED');
CREATE TABLE "User" ("id" TEXT NOT NULL PRIMARY KEY,"name" TEXT NOT NULL,"email" TEXT NOT NULL UNIQUE,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL,"extension" TEXT,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Campaign" ("id" TEXT NOT NULL PRIMARY KEY,"name" TEXT NOT NULL,"description" TEXT,"status" "CampaignStatus" NOT NULL DEFAULT 'RASCUNHO',"responsibleId" TEXT,"allowedCallStart" TEXT NOT NULL DEFAULT '08:00',"allowedCallEnd" TEXT NOT NULL DEFAULT '18:00',"maxAttemptsPerLead" INTEGER NOT NULL DEFAULT 3,"minIntervalMinutes" INTEGER NOT NULL DEFAULT 60,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Lead" ("id" TEXT NOT NULL PRIMARY KEY,"name" TEXT NOT NULL,"phoneNormalized" TEXT NOT NULL,"phoneOriginal" TEXT NOT NULL,"cpf" TEXT,"email" TEXT,"course" TEXT,"origin" TEXT,"notes" TEXT,"campaignId" TEXT NOT NULL,"operatorId" TEXT,"status" "LeadStatus" NOT NULL DEFAULT 'NOVO',"doNotCall" BOOLEAN NOT NULL DEFAULT false,"callbackAt" TIMESTAMP(3),"lastAttemptAt" TIMESTAMP(3),"attemptsCount" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("campaignId","phoneNormalized"));
CREATE INDEX "Lead_phoneNormalized_idx" ON "Lead"("phoneNormalized");
CREATE TABLE "CallAttempt" ("id" TEXT NOT NULL PRIMARY KEY,"leadId" TEXT NOT NULL,"campaignId" TEXT NOT NULL,"operatorId" TEXT NOT NULL,"startedAt" TIMESTAMP(3),"endedAt" TIMESTAMP(3),"durationSeconds" INTEGER,"provider" TEXT NOT NULL,"providerCallId" TEXT,"status" "CallStatus" NOT NULL DEFAULT 'CREATED',"finalDisposition" "LeadStatus","notes" TEXT,"errorMessage" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ImportLog" ("id" TEXT NOT NULL PRIMARY KEY,"campaignId" TEXT NOT NULL,"fileName" TEXT NOT NULL,"totalRead" INTEGER NOT NULL,"totalImported" INTEGER NOT NULL,"duplicates" INTEGER NOT NULL,"invalid" INTEGER NOT NULL,"blocked" INTEGER NOT NULL,"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "DoNotCall" ("id" TEXT NOT NULL PRIMARY KEY,"phoneNormalized" TEXT NOT NULL UNIQUE,"reason" TEXT,"blockedById" TEXT,"blockedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AuditLog" ("id" TEXT NOT NULL PRIMARY KEY,"userId" TEXT,"action" TEXT NOT NULL,"entity" TEXT,"entityId" TEXT,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "VoipConfig" ("id" TEXT NOT NULL PRIMARY KEY,"provider" TEXT NOT NULL DEFAULT 'mock',"asteriskHost" TEXT,"asteriskPort" INTEGER,"asteriskUsername" TEXT,"asteriskContext" TEXT,"asteriskTrunk" TEXT,"operatorPrefix" TEXT,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
ALTER TABLE "Campaign" ADD CONSTRAINT "Campaign_responsibleId_fkey" FOREIGN KEY ("responsibleId") REFERENCES "User"("id");
ALTER TABLE "Lead" ADD CONSTRAINT "Lead_campaignId_fkey" FOREIGN KEY ("campaignId") REFERENCES "Campaign"("id") ON DELETE CASCADE;
ALTER TABLE "Lead" ADD CONSTRAINT "Lead_operatorId_fkey" FOREIGN KEY ("operatorId") REFERENCES "User"("id");
ALTER TABLE "CallAttempt" ADD CONSTRAINT "CallAttempt_leadId_fkey" FOREIGN KEY ("leadId") REFERENCES "Lead"("id") ON DELETE CASCADE;
ALTER TABLE "CallAttempt" ADD CONSTRAINT "CallAttempt_campaignId_fkey" FOREIGN KEY ("campaignId") REFERENCES "Campaign"("id");
ALTER TABLE "CallAttempt" ADD CONSTRAINT "CallAttempt_operatorId_fkey" FOREIGN KEY ("operatorId") REFERENCES "User"("id");
ALTER TABLE "ImportLog" ADD CONSTRAINT "ImportLog_campaignId_fkey" FOREIGN KEY ("campaignId") REFERENCES "Campaign"("id") ON DELETE CASCADE;
ALTER TABLE "AuditLog" ADD CONSTRAINT "AuditLog_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id");
